/**
 * Debug logger for pi-speak extension.
 *
 * Writes timestamped messages to the log file specified in config.
 * Can be disabled by setting PI_SPEAK_DEBUG=0 in the environment.
 */

import { appendFileSync, existsSync, statSync, truncateSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";

/** Default debug log path */
const DEFAULT_LOG_PATH = join(homedir(), ".pi-speak-debug.log");
/** Default max log size in bytes (2 MB) */
const DEFAULT_LOG_MAX_BYTES = 2 * 1024 * 1024;

let _logPath = DEFAULT_LOG_PATH;
let _maxLogBytes = DEFAULT_LOG_MAX_BYTES;
let _enabled = process.env.PI_SPEAK_DEBUG !== "0";

/** Configure debug logger from config */
export function configureDebug(config: { enabled: boolean; logPath: string; logMaxBytes: number }): void {
  _enabled = config.enabled;
  _logPath = config.logPath.startsWith("~") ? join(homedir(), config.logPath.slice(1)) : config.logPath;
  _maxLogBytes = config.logMaxBytes;
}

/** Set debug logging enabled/disabled (e.g., from config.debug) */
export function setDebugEnabled(enabled: boolean): void {
  _enabled = enabled;
}

/** Rotate log if it exceeds max size */
function maybeRotate(): void {
  try {
    if (!existsSync(_logPath)) return;
    const stat = statSync(_logPath);
    if (stat.size >= _maxLogBytes) {
      truncateSync(_logPath, 0);
    }
  } catch (err) {
    console.warn(`[pi-speak] debug: failed to rotate log: ${err instanceof Error ? err.message : String(err)}`);
  }
}

export function debug(msg: string): void {
  if (!_enabled) return;
  maybeRotate();
  const ts = new Date().toISOString();
  try {
    appendFileSync(_logPath, `[${ts}] ${msg}\n`);
  } catch (err) {
    // Fallback to console when file logging fails
    console.log(`[pi-speak] ${msg}`);
    console.warn(`[pi-speak] debug: failed to write to log file: ${err instanceof Error ? err.message : String(err)}`);
  }
}

/** Log an error with full stack trace */
export function debugError(msg: string, err: unknown): void {
  if (!_enabled) return;
  const detail = err instanceof Error ? `${err.message}\n${err.stack ?? ""}` : String(err);
  debug(`${msg}: ${detail}`);
}

/**
 * LLM-powered summarizer for pi-speak notification ping.
 *
 * Uses OpenRouter API with a cheap fast model to generate
 * a 2-sentence "what was done, where" summary for the voice ping.
 */

import type { SpeakConfig } from "./config/v1/schema";
import { debug, debugError } from "./debug";

const OPENROUTER_URL = "https://openrouter.ai/api/v1/chat/completions";

export interface SummarizeContext {
  /** What the assistant did (truncated text of the response) */
  responseText: string;
  /** tmux session name (if available) */
  sessionName?: string;
  /** Config for the summarizer */
  config: SpeakConfig["summarizer"];
  /** API key override */
  apiKey?: string;
  /** Fallback text */
  fallbackText: string;
}

/** Call OpenRouter with a system prompt and user message */
async function callOpenRouter(opts: {
  systemPrompt: string;
  userMessage: string;
  model: string;
  maxTokens: number;
  timeoutMs: number;
  apiKey: string;
}): Promise<string | null> {
  const response = await fetch(OPENROUTER_URL, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${opts.apiKey}`
    },
    body: JSON.stringify({
      model: opts.model,
      max_tokens: opts.maxTokens,
      messages: [
        { role: "system", content: opts.systemPrompt },
        { role: "user", content: opts.userMessage }
      ]
    }),
    signal: AbortSignal.timeout(opts.timeoutMs)
  });

  if (!response.ok) {
    debug(`openrouter: error ${response.status}`);
    return null;
  }

  const data = (await response.json()) as { choices?: Array<{ message?: { content?: string } }> };
  return data.choices?.[0]?.message?.content?.trim() || null;
}

/** Generate a 2-sentence voice ping summary via OpenRouter */
export async function summarizeForPing(ctx: SummarizeContext): Promise<string> {
  if (!ctx.config.enabled) {
    debug("summarizer: disabled — using fallback summary");
    return fallbackSummary(ctx);
  }

  const apiKey = ctx.apiKey ?? process.env.OPENROUTER_API_KEY;
  if (!apiKey) {
    debug("summarizer: no OPENROUTER_API_KEY — using fallback summary");
    return fallbackSummary(ctx);
  }

  const where = ctx.sessionName ? ` in the "${ctx.sessionName}" session` : "";

  try {
    const summary = await callOpenRouter({
      systemPrompt: ctx.config.prompt,
      userMessage: `Write a voice notification: what was done${where}. What: ${ctx.responseText.slice(0, 500)}`,
      model: ctx.config.model,
      maxTokens: ctx.config.maxTokens,
      timeoutMs: ctx.config.timeoutMs,
      apiKey
    });

    if (!summary) {
      debug("summarizer: empty response from OpenRouter");
      return fallbackSummary(ctx);
    }

    debug(`summarizer: LLM summary = "${summary}"`);
    return summary;
  } catch (err) {
    debugError("summarizer: fetch failed", err);
    return fallbackSummary(ctx);
  }
}

/** Fallback: simple truncate-based summary if LLM is unavailable */
function fallbackSummary(ctx: SummarizeContext): string {
  const where = ctx.sessionName ? ` in ${ctx.sessionName}` : "";
  const preview = ctx.responseText.slice(0, 100).replace(/\n/g, " ").trim();
  return `${ctx.fallbackText}${where}. ${preview}…`;
}

/**
 * Unreal Speech TTS client for pi-speak extension.
 *
 * Uses the V8 /stream endpoint for low-latency MP3 generation.
 * Responses are cached to disk for instant replay.
 */

import { type ChildProcess } from "node:child_process";
import { existsSync, unlinkSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import type { SpeakConfig } from "./config/v1/schema";
import { debug } from "./debug";
import { chunkBySentences } from "./helpers";
import type { UI } from "./index";
import type { Platform } from "./platform";

const TEMP_FILE_PREFIX = "pi-speak-";

/** Readback configuration — the voice/audio subset of SpeakConfig */
export interface ReadbackConfig {
  voiceId: string;
  bitrate: string;
  speed: number;
  pitch: number;
}

const DEFAULT_READBACK_CONFIG: ReadbackConfig = {
  voiceId: "Sierra",
  bitrate: "192k",
  speed: 0,
  pitch: 1.0
};

/** Default max chunk size */
const DEFAULT_MAX_CHUNK_CHARS = 900;

/** Fetch MP3 audio from Unreal Speech /stream endpoint */
async function fetchTTS(text: string, config: ReadbackConfig): Promise<Buffer> {
  const apiKey = process.env.UNREAL_SPEECH_API_KEY;
  if (!apiKey) throw new Error("UNREAL_SPEECH_API_KEY not set");

  const response = await fetch("https://api.v8.unrealspeech.com/stream", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`
    },
    body: JSON.stringify({
      Text: text,
      VoiceId: config.voiceId,
      Bitrate: config.bitrate,
      Speed: config.speed,
      Pitch: config.pitch
    }),
    signal: AbortSignal.timeout(10_000)
  });

  if (!response.ok) {
    const body = await response.text();
    throw new Error(`Unreal Speech API error ${response.status}: ${body}`);
  }

  const arrayBuf = await response.arrayBuffer();
  return Buffer.from(arrayBuf);
}

/**
 * Stateful TTS playback manager with caching and generation-based cancellation.
 *
 * Note: speak() is not re-entrant — callers should await speak() before calling again.
 * Concurrent calls will cause race conditions on cachedAudioFiles.
 */
export class TTSPlayer {
  private cachedAudioFiles: string[] = [];
  private currentPlayback: ChildProcess | null = null;
  private isPlaying = false;
  private playGeneration = 0;
  private config: ReadbackConfig;
  private maxChunkChars: number;
  private shortcutLabel: string;

  constructor(
    private platform: Platform,
    config?: SpeakConfig
  ) {
    this.config = {
      voiceId: config?.readback.voiceId ?? DEFAULT_READBACK_CONFIG.voiceId,
      bitrate: config?.readback.bitrate ?? DEFAULT_READBACK_CONFIG.bitrate,
      speed: config?.readback.speed ?? DEFAULT_READBACK_CONFIG.speed,
      pitch: config?.readback.pitch ?? DEFAULT_READBACK_CONFIG.pitch
    };
    this.maxChunkChars = config?.readback.maxChunkChars ?? DEFAULT_MAX_CHUNK_CHARS;
    this.shortcutLabel = config?.shortcut ?? "alt+r";
  }

  get playing(): boolean {
    return this.isPlaying;
  }

  get cachedFiles(): string[] {
    return this.cachedAudioFiles;
  }

  /** Delete all cached audio files */
  clearCache(): void {
    debug(`clearCache: deleting ${this.cachedAudioFiles.length} files`);
    for (const f of this.cachedAudioFiles) {
      try {
        unlinkSync(f);
        debug(`clearCache: deleted ${f}`);
      } catch (err: unknown) {
        debug(`clearCache: failed to delete ${f}: ${err instanceof Error ? err.message : String(err)}`);
      }
    }
    this.cachedAudioFiles = [];
  }

  /** Speak a short ping notification (not cached — does not affect alt+r replay). */
  async ping(text: string): Promise<void> {
    if (!text) return;

    debug(`ping: speaking "${text.slice(0, 80)}"`);

    try {
      const mp3Data = await fetchTTS(text, this.config);
      const tmpFile = join(tmpdir(), `${TEMP_FILE_PREFIX}ping-${Date.now()}.mp3`);
      writeFileSync(tmpFile, mp3Data);

      await this.platform.playAudio(tmpFile, proc => {
        this.currentPlayback = proc;
      });

      // Clean up ping temp file
      try {
        unlinkSync(tmpFile);
      } catch {
        /* ignore */
      }
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      debug(`ping: ERROR: ${message}`);
    }
  }

  /** Speak text aloud. Uses cached files if available, fetches otherwise. */
  async speak(text: string, ui: UI): Promise<void> {
    if (!text) return;

    const myGeneration = ++this.playGeneration;
    this.isPlaying = true;
    this.updateWidget(ui);

    const chunks = chunkBySentences(text, this.maxChunkChars);
    const newFiles: string[] = [];
    debug(`speak: gen=${myGeneration} chunks=${chunks.length} cachedFiles=${this.cachedAudioFiles.length}`);

    try {
      for (let i = 0; i < chunks.length; i++) {
        if (this.playGeneration !== myGeneration) {
          debug(`speak: gen=${myGeneration} aborted at chunk ${i} (current gen=${this.playGeneration})`);
          break;
        }

        const existingFile = this.cachedAudioFiles[i];
        let playFile: string;

        if (existingFile && existsSync(existingFile)) {
          playFile = existingFile;
          debug(`speak: gen=${myGeneration} chunk ${i}: CACHE HIT → ${playFile}`);
        } else {
          debug(`speak: gen=${myGeneration} chunk ${i}: FETCHING from Unreal Speech...`);
          const chunk = chunks[i];
          if (chunk === undefined) break;
          const mp3Data = await fetchTTS(chunk, this.config);

          if (this.playGeneration !== myGeneration) {
            debug(`speak: gen=${myGeneration} aborted after fetch at chunk ${i}`);
            break;
          }
          playFile = join(tmpdir(), `${TEMP_FILE_PREFIX}${Date.now()}-${i}.mp3`);
          writeFileSync(playFile, mp3Data);
          debug(`speak: gen=${myGeneration} chunk ${i}: FETCHED → ${playFile} (${mp3Data.length} bytes)`);
        }

        newFiles.push(playFile);

        if (this.playGeneration !== myGeneration) break;

        await this.platform.playAudio(playFile, proc => {
          this.currentPlayback = proc;
        });
      }
    } catch (err: unknown) {
      if (this.playGeneration === myGeneration) {
        const message = err instanceof Error ? err.message : String(err);
        debug(`speak: gen=${myGeneration} ERROR: ${message}`);
        ui.notify(`speak: TTS error — ${message}`, "error");
      }
    } finally {
      if (this.playGeneration === myGeneration) {
        this.isPlaying = false;
        this.currentPlayback = null;

        // Replace cache with the files we just produced/used
        const oldFiles = this.cachedAudioFiles.filter(f => !newFiles.includes(f));
        for (const f of oldFiles) {
          try {
            unlinkSync(f);
          } catch {
            /* ignore */
          }
        }
        this.cachedAudioFiles = newFiles;
        debug(
          `speak: gen=${myGeneration} done. cachedFiles=${this.cachedAudioFiles.length} path=${this.cachedAudioFiles[0] ?? "none"}`
        );

        this.updateWidget(ui);
      } else {
        // Aborted — clean up any files we fetched but didn't cache
        for (const f of newFiles) {
          try {
            unlinkSync(f);
          } catch {
            /* ignore */
          }
        }
        debug(`speak: gen=${myGeneration} aborted, cleaned up ${newFiles.length} orphaned files`);
      }
    }
  }

  /** Stop current playback (does not restart) */
  stop(): void {
    this.playGeneration++; // Invalidate any running speak so its finally block is a no-op
    this.isPlaying = false;
    if (this.currentPlayback) {
      this.currentPlayback.kill("SIGTERM");
      // Fallback to SIGKILL if process doesn't stop within 500ms
      const proc = this.currentPlayback;
      setTimeout(() => {
        if (!proc.killed) {
          debug("stop: SIGTERM didn't work, sending SIGKILL");
          proc.kill("SIGKILL");
        }
      }, 500);
      this.currentPlayback = null;
    }
  }

  /** Update the status widget */
  private updateWidget(ui: Pick<UI, "setWidget">, disabled = false): void {
    if (disabled) {
      ui.setWidget("speak", undefined);
      return;
    }
    if (this.isPlaying) {
      ui.setWidget("speak", [`🔊 Speaking…  ${this.shortcutLabel} stop`]);
    } else if (this.cachedAudioFiles.length > 0) {
      ui.setWidget("speak", [`🔊 Ready  ${this.shortcutLabel} replay`]);
    } else {
      ui.setWidget("speak", [`🔊 ${this.shortcutLabel} read aloud`]);
    }
  }
}

/**
 * pi-speak — Voice readback extension for Pi
 *
 * When the agent finishes a turn, this extension:
 *   1. Speaks a short voice ping: what was done + which tmux session
 *   2. Registers alt+r (or configured shortcut) to replay / stop the last response
 *   3. Shows a status widget below the editor
 *
 * Settings: see ~/.config/pi-speak/config.json
 * API key: set UNREAL_SPEECH_API_KEY in your environment (source ~/.env in your shell)
 * Optional: OPENROUTER_API_KEY for smarter voice ping summaries
 */

import { execSync } from "node:child_process";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { z } from "zod";
import { loadConfig, revalidateConfig } from "./config/index";
import { defaultConfig } from "./config/v1/schema";
import { configureDebug, debug, debugError, setDebugEnabled } from "./debug";
import { stripMarkdown } from "./helpers";
import { createPlatform, isMacMuted, isPlatformSupported } from "./platform";
import { summarizeForPing } from "./summarizer";
import { TTSPlayer } from "./tts";

export interface UI {
  setWidget(key: string, content: string[] | undefined): void;
  notify(msg: string, type: "info" | "warning" | "error"): void;
}

export default function (pi: ExtensionAPI) {
  const { config, error: initialError } = loadConfig(defaultConfig);

  setDebugEnabled(config.debug.enabled);
  configureDebug(config.debug);

  // Warn if platform is not supported (defer until session_start to have access to ctx.ui)
  const platformNotSupported = !isPlatformSupported();

  const platform = createPlatform();
  const player = new TTSPlayer(platform, config);

  // ── State ──────────────────────────────────────────────────────────────────

  let configError: z.ZodError | Error | null = initialError;
  let lastResponseText = "";
  let disabled = false;
  let sessionName = "";
  let wasMutedOnLastResponse = false;

  // ── Extract assistant text ────────────────────────────────────────────────

  function extractAssistantText(
    messages: Array<{ role?: string; content?: string | Array<{ type: string; text?: string }> }>
  ): string {
    for (let i = messages.length - 1; i >= 0; i--) {
      const msg = messages[i];
      if (msg?.role !== "assistant") continue;

      const textParts: string[] = [];
      const content = msg.content;

      if (typeof content === "string") {
        textParts.push(content);
      } else if (Array.isArray(content)) {
        for (const block of content) {
          if (block.type === "text" && typeof block.text === "string") {
            textParts.push(block.text);
          }
        }
      }

      if (textParts.length > 0) {
        return stripMarkdown(textParts.join("\n"));
      }
    }
    return "";
  }

  /** Build widget content: validation errors first, then normal status */
  function buildWidgetContent(normalLine: string): string[] {
    if (!configError) return [normalLine];

    if (configError instanceof z.ZodError) {
      const errorLines = configError.issues.map(issue => `⚠️ ${issue.path.join(".") || "root"}: ${issue.message}`);
      return [...errorLines, normalLine];
    }

    return [`⚠️ ${configError.message}`, normalLine];
  }

  // ── Session start ─────────────────────────────────────────────────────────

  pi.on("session_start", async (event, ctx) => {
    debug("=== session_start ===");

    // Warn if platform is not supported
    if (platformNotSupported) {
      debug(`platform "${process.platform}" is not supported — audio playback disabled`);
      ctx.ui.notify(
        `speak: platform "${process.platform}" is not supported. Only macOS is supported for audio playback.`,
        "warning"
      );
      ctx.ui.setWidget("speak", ["🔊 Platform not supported"]);
    }

    // Check if system is muted
    if (isMacMuted()) {
      debug("session_start: system is muted — voice readback will be skipped");
      ctx.ui.notify("speak: system is muted — voice readback disabled. Unmute to enable.", "warning");
    }

    // Capture session name for voice ping
    if (process.env.TMUX_PANE) {
      try {
        sessionName = execSync(`tmux display-message -p -t '${process.env.TMUX_PANE}' '#{session_name}'`, {
          encoding: "utf-8",
          stdio: ["pipe", "pipe", "pipe"]
        }).trim();
      } catch {
        sessionName = "";
      }
    }

    // Check for required API key (should be set in user's environment)
    const apiKey = process.env.UNREAL_SPEECH_API_KEY ?? config.api.unrealSpeechKey;
    if (!apiKey) {
      disabled = true;
      debug("session_start: NO API KEY — extension disabled");
      ctx.ui.notify(
        "speak: UNREAL_SPEECH_API_KEY not set — voice readback disabled. Set it in your environment (e.g., source ~/.env)",
        "warning"
      );
      ctx.ui.setWidget("speak", undefined);
      return;
    }

    // Clear stale audio cache from previous sessions
    player.clearCache();

    debug("session_start: API key loaded, extension enabled");
    ctx.ui.setWidget("speak", buildWidgetContent("🔊 " + config.shortcut + " read aloud"));
  });

  // ── Input: revalidate config on user input ────────────────────────────────

  pi.on("input", async () => {
    // Re-read and re-validate config to detect fixes without reloading
    configError = revalidateConfig();
  });

  // ── Agent end ─────────────────────────────────────────────────────────────

  pi.on("agent_end", async (event, ctx) => {
    debug("=== agent_end ===");
    if (disabled) {
      debug("agent_end: SKIPPED (disabled)");
      return;
    }

    // Check mute status dynamically to save API costs
    const muted = isMacMuted();
    wasMutedOnLastResponse = muted;

    if (muted) {
      debug("agent_end: SKIPPED (system is muted)");
      ctx.ui.setWidget("speak", buildWidgetContent("🔇 Muted  " + config.shortcut + " replay"));
      return;
    }

    const text = extractAssistantText(event.messages);
    debug(`agent_end: extracted text length=${text.length} preview="${text.slice(0, 80)}"`);
    if (!text) {
      debug("agent_end: no assistant text — skipping");
      return;
    }

    // Clear cached audio from previous response (conversation moved on)
    if (text !== lastResponseText) {
      debug(`agent_end: new response (${text.length} chars), clearing old cache`);
      player.clearCache();
    }
    lastResponseText = text;
    ctx.ui.setWidget("speak", buildWidgetContent("🔊 Ready  " + config.shortcut + " replay"));

    // Skip ping if summarizer disabled
    if (!config.summarizer.enabled) {
      debug("agent_end: summarizer disabled — skipping ping");
      return;
    }

    // Generate short voice ping summary (LLM if OpenRouter key, else fallback)
    const ping = await summarizeForPing({
      responseText: text,
      sessionName: sessionName || undefined,
      config: config.summarizer,
      apiKey: config.api.openRouterKey ?? undefined,
      fallbackText: config.summarizer.fallbackText
    });
    debug(`agent_end: voice ping = "${ping}"`);

    // Speak the ping (short, not cached — alt+r replays the full response)
    player.ping(ping);
  });

  // ── Shortcut: replay / stop ─────────────────────────────────────────────

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  pi.registerShortcut(config.shortcut as any, {
    description: "Replay last response aloud / stop current playback",
    handler: ctx => {
      debug(`=== shortcut: ${config.shortcut} pressed ===`);
      if (disabled) {
        debug(`shortcut: SKIPPED (disabled)`);
        return;
      }

      if (isMacMuted()) {
        debug(`shortcut: SKIPPED (system is muted)`);
        ctx.ui.notify("speak: system is muted — unmute to hear responses", "info");
        return;
      }

      if (player.playing) {
        debug(`shortcut: STOP (was playing)`);
        player.stop();
        ctx.ui.setWidget("speak", buildWidgetContent("🔊 Ready  " + config.shortcut + " replay"));
        return;
      }

      if (!lastResponseText) {
        debug(`shortcut: no response to replay`);
        ctx.ui.notify("speak: no response to replay yet", "info");
        return;
      }

      // Check if we need to regenerate (was muted when response came)
      if (wasMutedOnLastResponse || player.cachedFiles.length === 0) {
        debug(`shortcut: regenerating audio (was muted or no cache)`);
        ctx.ui.setWidget("speak", buildWidgetContent("🔊 Generating...  " + config.shortcut + " stop"));
        player.speak(lastResponseText, ctx.ui);
        return;
      }

      debug(`shortcut: REPLAY (text length=${lastResponseText.length})`);
      try {
        player.speak(lastResponseText, ctx.ui);
      } catch (err) {
        debugError("shortcut: speak() threw", err);
        ctx.ui.notify(`speak: replay error — ${err instanceof Error ? err.message : String(err)}`, "error");
      }
    }
  });
}

import { z } from "zod";

const SCHEMA_URL = "https://raw.githubusercontent.com/nikbrunner/pi-speak/main/src/config/v1/schema.json";

const CONFIG_DIR = `${process.env.HOME}/.config/pi-speak`;
export const CONFIG_PATH = `${CONFIG_DIR}/config.json`;

// ─── Voice IDs ──────────────────────────────────────────────────────────────
// https://docs.v8.unrealspeech.com/

const VoiceId = z.enum([
  // American Female
  "Autumn",
  "Melody",
  "Hannah",
  "Emily",
  "Ivy",
  "Kaitlyn",
  "Luna",
  "Willow",
  "Lauren",
  "Sierra",
  // American Male
  "Noah",
  "Jasper",
  "Caleb",
  "Ronan",
  "Ethan",
  "Daniel",
  "Zane",
  // Chinese Female
  "Mei",
  "Lian",
  "Ting",
  "Jing",
  // Chinese Male
  "Wei",
  "Jian",
  "Hao",
  "Sheng",
  // Spanish Female
  "Lucía",
  // Spanish Male
  "Mateo",
  "Javier",
  // French Female
  "Élodie",
  // Hindi Female
  "Ananya",
  "Priya",
  // Hindi Male
  "Arjun",
  "Rohan",
  // Italian Female
  "Giulia",
  // Italian Male
  "Luca",
  // Portuguese Female
  "Camila",
  // Portuguese Male
  "Thiago",
  "Rafael"
]);

const Bitrate = z.enum(["16k", "32k", "48k", "64k", "128k", "192k", "256k", "320k"]);

// ─── Sub-schemas ─────────────────────────────────────────────────────────────

export const ReadbackConfigSchema = z.object({
  voiceId: VoiceId.describe("Unreal Speech voice name").default("Sierra"),
  bitrate: Bitrate.describe("Audio bitrate — lower saves bandwidth, higher improves fidelity").default("192k"),
  speed: z.number().min(-1).max(1).describe("Speech speed adjustment (-1 to 1)").default(0),
  pitch: z.number().min(0.5).max(1.5).describe("Speech pitch adjustment (0.5 to 1.5)").default(1.0),
  maxChunkChars: z
    .number()
    .int()
    .min(1)
    .max(1000)
    .describe("Max characters per TTS chunk (Unreal Speech limit is 1000)")
    .default(900)
});

export const SummarizerConfigSchema = z.object({
  enabled: z.boolean().describe("Use LLM to summarize agent output for voice notification").default(true),
  model: z.string().describe("OpenRouter model ID for summarization").default("google/gemini-2.5-flash-lite"),
  maxTokens: z.number().int().min(1).max(500).describe("Max tokens for summarizer response").default(150),
  timeoutMs: z.number().int().min(1000).max(60000).describe("Summarizer request timeout in milliseconds").default(5000),
  prompt: z
    .string()
    .describe("System prompt for the summarizer LLM")
    .default(
      "You just watched a developer and their AI agent work together. Say what they built, fixed, or changed — in one natural sentence, like you're leaning over to tell a teammate. Casual tone. No praise, no evaluation, just the facts. Session name first if provided."
    ),
  fallbackText: z
    .string()
    .describe("Fallback text when summarizer is disabled or fails")
    .default("Work done. Code better now.")
});

export const DebugConfigSchema = z.object({
  enabled: z.boolean().describe("Enable debug logging to file").default(true),
  logPath: z.string().describe("Path to the debug log file").default("~/.pi-speak-debug.log"),
  logMaxBytes: z
    .number()
    .int()
    .min(1024)
    .max(10 * 1024 * 1024)
    .describe("Max log file size in bytes before rotation")
    .default(2 * 1024 * 1024)
});

export const ApiConfigSchema = z.object({
  unrealSpeechKey: z.string().nullable().describe("Unreal Speech API key (env var takes precedence)").default(null),
  openRouterKey: z.string().nullable().describe("OpenRouter API key (env var takes precedence)").default(null)
});

// ─── Main schema ─────────────────────────────────────────────────────────────

export const SpeakConfigSchema = z.object({
  $schema: z.url().default(SCHEMA_URL),
  version: z.number().int().min(0).default(1),
  shortcut: z.string().describe("Keyboard shortcut for replay/stop").default("alt+r"),
  readback: ReadbackConfigSchema.prefault({}),
  summarizer: SummarizerConfigSchema.prefault({}),
  debug: DebugConfigSchema.prefault({}),
  api: ApiConfigSchema.prefault({})
});

export const defaultConfig = SpeakConfigSchema.parse({});

export type SpeakConfig = z.infer<typeof SpeakConfigSchema>;

/**
 * Shared helpers for pi-speak extension.
 */

/** Strip markdown formatting for cleaner speech */
export function stripMarkdown(text: string): string {
  return (
    text
      // Remove fenced code blocks entirely (reading code aloud is terrible)
      .replace(/```[\s\S]*?```/g, "")
      // Remove markdown tables (converted to nothing — too noisy spoken)
      .replace(/^\|.*\|$/gm, "")
      // Remove table separator/delimiter rows
      .replace(/^\|[\s:-]+\|$/gm, "")
      // Remove inline code backticks, keep the content (short names are fine spoken)
      .replace(/`([^`]+)`/g, "$1")
      // Remove bold/italic markers
      .replace(/\*{1,3}([^*]+)\*{1,3}/g, "$1")
      .replace(/_{1,3}([^_]+)_{1,3}/g, "$1")
      // Remove strikethrough
      .replace(/~~([^~]+)~~/g, "$1")
      // Remove links, keep text
      .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
      // Remove headers markers
      .replace(/^#{1,6}\s+/gm, "")
      // Remove horizontal rules
      .replace(/^---+$/gm, "")
      // Remove list markers
      .replace(/^\s*[-*+]\s+/gm, "")
      .replace(/^\s*\d+\.\s+/gm, "")
      // Remove HTML tags
      .replace(/<[^>]+>/g, "")
      // Collapse multiple blank lines (code/table removal leaves gaps)
      .replace(/\n{3,}/g, "\n\n")
      // Remove leading blank lines
      .replace(/^\n+/, "")
      .trim()
  );
}

/** Split text into chunks at sentence boundaries, each ≤ maxChars */
export function chunkBySentences(text: string, maxChars: number): string[] {
  const chunks: string[] = [];
  let current = "";

  // Split on sentence boundaries (., !, ?, followed by space or end)
  const sentences = text.split(/(?<=[.!?])\s+/);

  for (const sentence of sentences) {
    if (current.length === 0) {
      current = sentence;
    } else if (current.length + 1 + sentence.length <= maxChars) {
      current += " " + sentence;
    } else {
      chunks.push(current);
      current = sentence;
    }
  }

  if (current.length > 0) {
    chunks.push(current);
  }

  // If a single chunk exceeds maxChars (no sentence boundaries), hard-split at maxChars
  const result: string[] = [];
  for (const chunk of chunks) {
    if (chunk.length <= maxChars) {
      result.push(chunk);
    } else {
      // Hard split at word boundaries
      let remaining = chunk;
      while (remaining.length > 0) {
        if (remaining.length <= maxChars) {
          result.push(remaining);
          break;
        }
        let splitAt = remaining.lastIndexOf(" ", maxChars);
        if (splitAt === -1) splitAt = maxChars;
        result.push(remaining.slice(0, splitAt));
        remaining = remaining.slice(splitAt).trim();
      }
    }
  }

  return result;
}

/** Generate a one-line summary for notifications */
export function summarize(text: string, maxLen = 80): string {
  const firstLine = text.split("\n")[0] ?? "";
  if (firstLine.length <= maxLen) return firstLine;
  return firstLine.slice(0, maxLen - 1) + "…";
}

